// ============================================================
// SP4 HT Motors — Marcus Calidus Events code
// 59 live bindings across 7 motors. Each motor has 6 winding + 2 bearings (+ optional current).
// ============================================================
var series = (ctrl && ctrl.series) ? ctrl.series : [];



function latestOf(s) {
  if (!s) return null;
  if (s.datapoints && s.datapoints.length) {
    for (var i = s.datapoints.length - 1; i >= 0; i--) {
      var v = s.datapoints[i][0];
      if (v !== null && v !== undefined && !isNaN(v)) return v;
    }
  }
  if (s.stats) {
    if (s.stats.current !== undefined && s.stats.current !== null) return s.stats.current;
    if (s.stats.last    !== undefined && s.stats.last    !== null) return s.stats.last;
  }
  return null;
}
function fmt(v, d) { return (v===null||v===undefined||isNaN(v))?'--':Number(v).toFixed(d); }
function setAttr(id, attr, val) { var e=svgnode.getElementById(id); if(e) e.setAttribute(attr, val); }
function setText(id, txt)       { var e=svgnode.getElementById(id); if(e) e.textContent = txt; }



var COLOR = { normal:'#22c55e', warning:'#f59e0b', critical:'#ef4444', nodata:'#64748b' };



// Heat-map: 40°C blue → 100 green → 130 amber → 155 red
function tempColor(v) {
  if (v===null || v===undefined || isNaN(v)) return '#1e293b';
  var stops = [
    {p:40,  c:[34,211,238]},
    {p:80,  c:[34,197,94]},
    {p:120, c:[245,158,11]},
    {p:155, c:[239,68,68]}
  ];
  var x = Math.max(stops[0].p, Math.min(stops[stops.length-1].p, v));
  for (var i = 0; i < stops.length - 1; i++) {
    if (x <= stops[i+1].p) {
      var a = stops[i], b = stops[i+1];
      var t = (x - a.p) / (b.p - a.p);
      var r  = Math.round(a.c[0] + (b.c[0]-a.c[0])*t);
      var g  = Math.round(a.c[1] + (b.c[1]-a.c[1])*t);
      var bl = Math.round(a.c[2] + (b.c[2]-a.c[2])*t);
      return 'rgb(' + r + ',' + g + ',' + bl + ')';
    }
  }
  return '#ef4444';
}



function rankOf(level) {
  return level === 'critical' ? 3 : level === 'warning' ? 2 : level === 'normal' ? 1 : 0;
}
function rankToColor(r) {
  return r === 3 ? COLOR.critical : r === 2 ? COLOR.warning : r === 1 ? COLOR.normal : COLOR.nodata;
}



var level, v;
var values = {};
var levels = {};        // per-binding level for rollups
var counts = { normal:0, warning:0, critical:0, nodata:0 };





// [0] e6022_w1 (E6022_CH1_WINDING_TEMPERATURE)
v = latestOf(series[0]);
values['e6022_w1'] = v;
level = (v===null)?'nodata':(v>155?'critical':(v>=130?'warning':'normal'));
levels['e6022_w1'] = level;
counts[level]++;
setText('e6022_w1_value', fmt(v, 0));
setAttr('e6022_w1_dot', 'fill', tempColor(v));
setAttr('e6022_w1_dot', 'stroke', COLOR[level]);



