(function() {
  var totalBindings = 59;
  var live = counts.normal + counts.warning + counts.critical;



  // Motors with at least one live binding
  var motorsLive = 0;
  motorIds.forEach(function(mid) {
    var anyLive = false;
    Object.keys(levels).forEach(function(k) {
      if (k.startsWith(mid + '_') && levels[k] !== 'nodata') anyLive = true;
    });
    if (anyLive) motorsLive++;
  });



  setText('fleet_live_value', motorsLive + '/7');
  setText('fleet_live_pct', Math.round((motorsLive / 7) * 100) + '%');
  setText('fleet_warn_value', counts.warning);
  setText('fleet_crit_value', counts.critical);
  var pctNormal = live > 0 ? Math.round((counts.normal / live) * 100) : 0;
  setText('fleet_health_value', pctNormal + '%');
  var hv = svgnode.getElementById('fleet_health_value');
  if (hv) {
    if      (counts.critical > 0) hv.setAttribute('fill', COLOR.critical);
    else if (counts.warning  > 0) hv.setAttribute('fill', COLOR.warning);
    else if (live === 0)          hv.setAttribute('fill', COLOR.nodata);
    else                          hv.setAttribute('fill', COLOR.normal);
  }
  setText('fleet_health_status_text',
    counts.critical > 0 ? 'CRITICAL — investigate' :
    counts.warning  > 0 ? 'WARNING' :
    live === 0          ? 'NO DATA' : 'NORMAL');
})();



