// ============================================================
// Per-motor status + winding summary stats
// ============================================================
var motorIds = ["e6022", "a1000", "e6023", "pdf", "e6024", "gsc3", "mnd"];
motorIds.forEach(function(mid){
  // Collect this motor's winding values for min/max/avg
  var wVals = [];
  for (var ch = 1; ch <= 6; ch++) {
    var v = values[mid + '_w' + ch];
    if (v !== null && v !== undefined && !isNaN(v)) wVals.push(v);
  }
  if (wVals.length > 0) {
    var mn = Math.min.apply(null, wVals);
    var mx = Math.max.apply(null, wVals);
    var sum = 0; for (var i=0;i<wVals.length;i++) sum += wVals[i];
    var av = sum / wVals.length;
    setText(mid + '_w_min', mn.toFixed(0));
    setText(mid + '_w_max', mx.toFixed(0));
    setText(mid + '_w_avg', av.toFixed(0));
  } else {
    setText(mid + '_w_min', '--');
    setText(mid + '_w_max', '--');
    setText(mid + '_w_avg', '--');
  }

  // Worst-of all signals on this motor: 6 windings + 2 bearings + (optional current)
  var motorIds_all = [];
  for (var ch = 1; ch <= 6; ch++) motorIds_all.push(mid + '_w' + ch);
  motorIds_all.push(mid + '_bear_de');
  motorIds_all.push(mid + '_bear_nde');
  if (levels.hasOwnProperty(mid + '_current')) motorIds_all.push(mid + '_current');

  var worst = 0;
  var hasAny = false;
  motorIds_all.forEach(function(id) {
    if (levels[id] === undefined) return;
    var r = rankOf(levels[id]);
    if (r > 0) hasAny = true;
    if (r > worst) worst = r;
  });
  var statusLabel = worst === 3 ? 'CRITICAL' : worst === 2 ? 'WARNING' : worst === 1 ? 'NORMAL' : 'NO DATA';
  setAttr(mid + '_motor_status_dot', 'fill', rankToColor(worst));
  setText(mid + '_motor_status_text', statusLabel);
  var stxt = svgnode.getElementById(mid + '_motor_status_text');
  if (stxt) stxt.setAttribute('fill', rankToColor(worst));
});

// ============================================================
// Fleet rollup KPIs
// ============================================================
(function() {
  var totalBindings = 59;
  var live = counts.normal + counts.warning + counts.critical;

  // Motors with at least one live binding
  var motorsLive = 0;
  motorIds.forEach(function(mid) {
    var anyLive = false;
    Object.keys(levels).forEach(function(k) {
      if (k.startsWith(mid + '_') && levels[k] !== 'nodata') anyLive = true;
    });
    if (anyLive) motorsLive++;
  });

  setText('fleet_live_value', motorsLive + '/7');
  setText('fleet_live_pct', Math.round((motorsLive / 7) * 100) + '%');
  setText('fleet_warn_value', counts.warning);
  setText('fleet_crit_value', counts.critical);
  var pctNormal = live > 0 ? Math.round((counts.normal / live) * 100) : 0;
  setText('fleet_health_value', pctNormal + '%');
  var hv = svgnode.getElementById('fleet_health_value');
  if (hv) {
    if      (counts.critical > 0) hv.setAttribute('fill', COLOR.critical);
    else if (counts.warning  > 0) hv.setAttribute('fill', COLOR.warning);
    else if (live === 0)          hv.setAttribute('fill', COLOR.nodata);
    else                          hv.setAttribute('fill', COLOR.normal);
  }
  setText('fleet_health_status_text',
    counts.critical > 0 ? 'CRITICAL — investigate' :
    counts.warning  > 0 ? 'WARNING' :
    live === 0          ? 'NO DATA' : 'NORMAL');
})();

